extends Node

## World Streamer — loads cells around the player, unloads distant ones.
## Uses non-blocking _process polling so threaded loads never freeze the game.

signal cell_loaded(cell_x: int, cell_z: int, node: Node)
signal cell_unloaded(cell_x: int, cell_z: int)
signal stream_complete

@export var cell_size: float = {{cell_size}}
@export var load_radius: int = {{load_radius}}

var _loaded_cells: Dictionary = {}  ## "x,z" → Node
var _pending_loads: Array[Dictionary] = []  ## [{key, path, cell_x, cell_z}]
var _player: Node3D = null
var _last_player_cell: Vector2i = Vector2i(99999, 99999)

func _ready():
	call_deferred("_find_player")

func _process(_delta: float) -> void:
	if _player == null:
		_find_player()
		return

	# Poll one pending load per frame (non-blocking)
	_poll_pending_loads()

	var cell := _world_to_cell(_player.global_position)
	if cell != _last_player_cell:
		_last_player_cell = cell
		_update_streaming(cell)

func _find_player() -> void:
	_player = get_tree().get_first_node_in_group("player")

func force_load_cell(cell_x: int, cell_z: int) -> void:
	var key := "%d,%d" % [cell_x, cell_z]
	if _loaded_cells.has(key):
		return
	for p in _pending_loads:
		if p.key == key:
			return
	_start_load(cell_x, cell_z)

func force_unload_cell(cell_x: int, cell_z: int) -> void:
	var key := "%d,%d" % [cell_x, cell_z]
	if not _loaded_cells.has(key):
		return
	_unload_cell(cell_x, cell_z)

func is_cell_loaded(cell_x: int, cell_z: int) -> bool:
	return ("%d,%d" % [cell_x, cell_z]) in _loaded_cells

func get_loaded_cell_count() -> int:
	return _loaded_cells.size()

func get_pending_count() -> int:
	return _pending_loads.size()

func reload_all() -> void:
	_pending_loads.clear()
	var keys := _loaded_cells.keys()
	for key in keys:
		var parts := key.split(",")
		_unload_cell(int(parts[0]), int(parts[1]))
	if _player:
		_last_player_cell = Vector2i(99999, 99999)  ## force refresh

func _update_streaming(player_cell: Vector2i) -> void:
	var radius := load_radius
	var unload_dist := int(ceil(radius * {{unload_margin}}))

	# Queue loads for cells within radius
	for x in range(player_cell.x - radius, player_cell.x + radius + 1):
		for z in range(player_cell.y - radius, player_cell.y + radius + 1):
			var key := "%d,%d" % [x, z]
			var already_loading := false
			for p in _pending_loads:
				if p.key == key:
					already_loading = true
					break
			if not _loaded_cells.has(key) and not already_loading:
				_start_load(x, z)

	# Queue unloads for cells beyond margin
	var to_unload: Array[Vector2i] = []
	for key in _loaded_cells:
		var parts := key.split(",")
		var cx := int(parts[0])
		var cz := int(parts[1])
		var dx := abs(cx - player_cell.x)
		var dz := abs(cz - player_cell.y)
		if max(dx, dz) > unload_dist:
			to_unload.append(Vector2i(cx, cz))

	for cell in to_unload:
		_unload_cell(cell.x, cell.y)

func _start_load(cell_x: int, cell_z: int) -> void:
	var key := "%d,%d" % [cell_x, cell_z]
	var path := "{{stream_path}}cell_%d_%d.tscn" % [cell_x, cell_z]
	var err := ResourceLoader.load_threaded_request(path)
	if err == OK:
		_pending_loads.append({
			"key": key,
			"path": path,
			"cell_x": cell_x,
			"cell_z": cell_z,
		})

func _poll_pending_loads() -> void:
	if _pending_loads.is_empty():
		return

	# Process one pending load per frame (non-blocking)
	var load_info := _pending_loads[0]
	var status := ResourceLoader.load_threaded_get_status(load_info.path)

	match status:
		ResourceLoader.THREAD_LOAD_IN_PROGRESS:
			return  # keep waiting
		ResourceLoader.THREAD_LOAD_FAILED:
			_pending_loads.pop_front()
		ResourceLoader.THREAD_LOAD_LOADED:
			_pending_loads.pop_front()
			var scene: PackedScene = ResourceLoader.load_threaded_get(load_info.path)
			var node := scene.instantiate()
			node.name = "Cell_%d_%d" % [load_info.cell_x, load_info.cell_z]
			add_child(node)
			_loaded_cells[load_info.key] = node
			cell_loaded.emit(load_info.cell_x, load_info.cell_z, node)
		_:  # THREAD_LOAD_INVALID_RESOURCE or unknown
			_pending_loads.pop_front()

func _unload_cell(cell_x: int, cell_z: int) -> void:
	var key := "%d,%d" % [cell_x, cell_z]
	if _loaded_cells.has(key):
		var node := _loaded_cells[key]
		_loaded_cells.erase(key)
		node.queue_free()
		cell_unloaded.emit(cell_x, cell_z)

func _world_to_cell(pos: Vector3) -> Vector2i:
	return Vector2i(int(floor(pos.x / cell_size)), int(floor(pos.z / cell_size)))
